const txt = typeof raw.text === 'string' ? raw.text.trim() : '';

if (!txt) {
  throw new Error("OpenAI output missing: $json.text is empty.");
}

// Parse JSON from text
let out;
try {
  out = JSON.parse(txt);
} catch (e) {
  // Try extracting JSON object if text is truncated/mixed (defensive)
  const start = txt.indexOf('{');
  const end = txt.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    const slice = txt.slice(start, end + 1);
    out = JSON.parse(slice);
  } else {
    throw new Error("OpenAI output is not valid JSON in $json.text.");
  }
}

const now = new Date().toISOString();

const safe = {
