  variables: Array.isArray(out.variables) ? out.variables : [],
  questions: [], // hard rule
  checklist_prereqs: Array.isArray(out.checklist_prereqs) ? out.checklist_prereqs : [],
  acceptance_tests: Array.isArray(out.acceptance_tests) ? out.acceptance_tests : [],
